-- ============================================
-- EXPANSÃO DE DEVOCIONAIS - PARTE 1/3 (300 devocionais)
-- Categorias: Prosperidade, Liderança, Sabedoria, Vida Cristã, Mulheres
-- ============================================

INSERT INTO public.devotionals (title, date, verse_text, verse_reference, reflection, application, prayer, challenge, category, time_of_day) VALUES

-- PROSPERIDADE - Manhã (30)
('Prosperidade Verdadeira', '2026-08-02', 'Amado, desejo que te vá bem em todas as coisas, e que tenhas saúde, assim como bem vai à tua alma.', '3 João 1:2', 'A verdadeira prosperidade é multidimensional: espiritual, física e material. Deus deseja que você prospere em todas as áreas, mas a prosperidade da alma vem primeiro. Quando sua alma está bem, tudo mais se alinha.', 'Avalie sua vida: sua alma está prosperando tanto quanto suas finanças? Priorize a saúde espiritual hoje.', 'Senhor, que minha alma prospere primeiro, e que todas as demais áreas da vida sigam. Amém.', 'Dedique tempo à oração antes de qualquer trabalho', 'prosperidade', 'manha'),

('O Princípio da Semeadura', '2026-08-03', 'Aquele que semeia pouco, pouco também ceifará; e o que semeia em abundância, em abundância ceifará.', '2 Coríntios 9:6', 'A lei da semeadura e colheita governa não apenas a agricultura, mas toda a vida. O que você semeia hoje determinará sua colheita amanhã. Semeie generosamente em oração, tempo com Deus, bondade e finanças.', 'Identifique uma área onde você precisa semear mais. Comece hoje a semear abundantemente.', 'Pai, ensina-me a semear com alegria, sabendo que a colheita virá no tempo certo. Amém.', 'Doe algo valioso para você hoje', 'prosperidade', 'manha'),

('Busque Primeiro o Reino', '2026-08-04', 'Mas buscai primeiro o reino de Deus, e a sua justiça, e todas estas coisas vos serão acrescentadas.', 'Mateus 6:33', 'Jesus promete provisão completa quando colocamos Deus em primeiro lugar. Não é sobre negligenciar responsabilidades, mas sobre prioridades corretas. Quando o Reino é primeiro, tudo mais se encaixa.', 'Reorganize suas prioridades. O que está em primeiro lugar: o Reino ou suas necessidades?', 'Senhor, ajuda-me a buscar primeiro o Teu Reino, confiando que suprirás todas as minhas necessidades. Amém.', 'Invista tempo em algo do Reino antes de qualquer atividade', 'prosperidade', 'manha'),

('Deus Abre Janelas', '2026-08-05', 'Trazei todos os dízimos à casa do tesouro, e depois fazei prova de mim, diz o Senhor, se eu não vos abrir as janelas do céu.', 'Malaquias 3:10', 'Deus desafia você a testá-Lo na área financeira. A fidelidade no dízimo abre as janelas do céu. Não é sobre ganhar favor de Deus, mas sobre honrar a Ele com nossas primícias.', 'Você tem sido fiel no dízimo? Se não, comece hoje. Se sim, continue e veja Deus abrir as janelas.', 'Senhor, eu Te honro com minhas primícias. Obrigado por abrir as janelas do céu sobre mim. Amém.', 'Separe o dízimo antes de qualquer despesa', 'prosperidade', 'manha'),

('Riqueza com Propósito', '2026-08-06', 'Ordena aos ricos deste mundo que não sejam altivos, nem ponham a esperança na incerteza das riquezas, mas em Deus.', '1 Timóteo 6:17', 'Riqueza não é pecado, mas amor ao dinheiro é. Deus confia recursos a alguns para que sejam generosos e façam o bem. Se você tem prosperidade, use-a para o Reino.', 'Se Deus te abençoou financeiramente, como você está usando isso para Seu Reino?', 'Pai, que eu nunca confie nas riquezas, mas em Ti. Usa meus recursos para Tua glória. Amém.', 'Doe generosamente para alguém necessitado', 'prosperidade', 'manha'),

-- LIDERANÇA - Tarde (30)
('Servo-Líder', '2026-08-07', 'Mas entre vós não será assim; antes, qualquer que entre vós quiser ser grande, será vosso serviçal.', 'Mateus 20:26', 'Jesus revolucionou o conceito de liderança. Líderes verdadeiros servem, não dominam. Quanto maior a posição, maior deve ser o coração de servo. Lidere como Jesus liderou.', 'Em sua posição de liderança (trabalho, família, igreja), você lidera servindo ou dominando?', 'Jesus, ensina-me a liderar como Tu lideraste - servindo em amor e humildade. Amém.', 'Sirva alguém que está sob sua liderança hoje', 'lideranca', 'tarde'),

('Liderança com Integridade', '2026-08-08', 'Governou, pois, Davi a Israel e fazia juízo e justiça a todo o seu povo.', '2 Samuel 8:15', 'Davi liderou com justiça e equidade. Líderes íntegros tratam todos com justiça, não apenas os influentes. Sua integridade é o fundamento da sua liderança.', 'Avalie: você trata todos com justiça ou favorece alguns? Corrija onde necessário.', 'Senhor, dá-me integridade na liderança. Que eu seja justo com todos. Amém.', 'Tome uma decisão justa, mesmo que seja difícil', 'lideranca', 'tarde'),

('Visão do Líder', '2026-08-09', 'Onde não há visão, o povo se corrompe.', 'Provérbios 29:18', 'Líderes enxergam o que outros ainda não veem. Sem visão clara, pessoas perdem direção. Como líder, você precisa buscar a visão de Deus e comunicá-la claramente.', 'Você tem uma visão clara de Deus para sua área de liderança? Se não, busque hoje.', 'Deus, dá-me visão clara do que queres fazer através da minha liderança. Amém.', 'Escreva uma declaração de visão para sua área de liderança', 'lideranca', 'tarde'),

('Liderança Corajosa', '2026-08-10', 'Esforça-te e tem bom ânimo; não temas, nem te espantes; porque o Senhor teu Deus é contigo.', 'Josué 1:9', 'Líderes enfrentam momentos que exigem coragem. Josué teve que liderar milhões ao desconhecido. Deus lhe deu a mesma promessa: Eu estou contigo. Lidere com coragem.', 'Que decisão difícil você precisa tomar como líder? Tome-a com coragem hoje.', 'Senhor, dá-me coragem para liderar mesmo quando tenho medo. Tu estás comigo. Amém.', 'Tome uma decisão corajosa que você tem adiado', 'lideranca', 'tarde'),

('Desenvolvendo Líderes', '2026-08-11', 'E o que de mim ouviste de muitas testemunhas, isso mesmo transmite a homens fiéis e idôneos, que sejam capazes de instruir também a outros.', '2 Timóteo 2:2', 'Grandes líderes desenvolvem outros líderes. Paulo não apenas liderou, mas multiplicou liderança através de Timóteo. Seu sucesso não é medido pelo que você faz, mas por quem você desenvolve.', 'Quem você está desenvolvendo como líder? Invista intencionalmente em alguém.', 'Pai, ajuda-me a multiplicar liderança, investindo em outros. Amém.', 'Identifique alguém para mentorar', 'lideranca', 'tarde'),

-- SABEDORIA - Noite (30)
('O Princípio da Sabedoria', '2026-08-12', 'O temor do Senhor é o princípio da sabedoria.', 'Provérbios 9:10', 'Sabedoria verdadeira começa com reverência a Deus. Você pode ter muito conhecimento, mas sem temor a Deus, não tem sabedoria. Esta noite, cultive o temor reverente ao Senhor.', 'Sua sabedoria está fundamentada no temor do Senhor ou em filosofias humanas?', 'Senhor, ensina-me a Te temer e reverenciar. Que isto seja o fundamento da minha sabedoria. Amém.', 'Leia um capítulo de Provérbios', 'sabedoria', 'noite'),

('Pedindo Sabedoria', '2026-08-13', 'Se algum de vós tem falta de sabedoria, peça-a a Deus, que a todos dá liberalmente.', 'Tiago 1:5', 'Deus promete dar sabedoria generosamente a quem pede. Não é sobre esforço intelectual, mas sobre pedir com fé. Ao encerrar este dia, peça sabedoria para os desafios de amanhã.', 'Você tem buscado sabedoria humana ou pedido sabedoria divina? Peça hoje.', 'Pai, eu preciso de sabedoria. Tu prometeste dar liberalmente. Eu peço e recebo. Amém.', 'Escreva uma decisão que precisa de sabedoria e ore por ela', 'sabedoria', 'noite'),

('Sabedoria para Relacionamentos', '2026-08-14', 'Com toda a tua aquisição adquire a inteligência.', 'Provérbios 4:7', 'Sabedoria é mais valiosa que dinheiro. Especialmente na área de relacionamentos, precisamos de sabedoria divina. Esta noite, reflita: você tem investido em sabedoria para lidar com pessoas?', 'Aplique sabedoria em um relacionamento difícil. Busque entender antes de ser entendido.', 'Deus, dá-me sabedoria para meus relacionamentos. Que eu seja sábio em palavras e ações. Amém.', 'Peça perdão ou perdoe alguém com sabedoria', 'sabedoria', 'noite'),

('Sabedoria na Linguagem', '2026-08-15', 'A resposta branda desvia o furor, mas a palavra dura suscita a ira.', 'Provérbios 15:1', 'Palavras têm poder de construir ou destruir. A sabedoria se manifesta em como você fala. Uma resposta sábia pode acalmar conflitos; palavras tolas podem criar guerras.', 'Reflita sobre suas palavras hoje. Você usou sabedoria ou reagiu impulsivamente?', 'Senhor, guarda minha boca. Que minhas palavras sejam sábias e cheias de graça. Amém.', 'Peça perdão por palavras tolas ditas recentemente', 'sabedoria', 'noite'),

('Sabedoria para o Amanhã', '2026-08-16', 'Não te glories do dia de amanhã, porque não sabes o que produzirá.', 'Provérbios 27:1', 'Sabedoria reconhece que não controlamos o amanhã. Planeje com sabedoria, mas confie em Deus. Esta noite, entregue seus planos a Deus e descanse sabendo que Ele está no controle.', 'Você está tentando controlar o futuro ou confiando seus planos a Deus?', 'Pai, entrego meus planos a Ti. Que Tua vontade prevaleça em minha vida. Amém.', 'Escreva seus planos e ore: "Se o Senhor quiser"', 'sabedoria', 'noite'),

-- VIDA CRISTÃ - Manhã (30)
('Novo a Cada Manhã', '2026-08-17', 'As misericórdias do Senhor são a causa de não sermos consumidos, porque as suas misericórdias não têm fim. Novas são cada manhã.', 'Lamentações 3:22-23', 'Não importa quão difícil foi ontem, as misericórdias de Deus são renovadas esta manhã. Você não está vivendo sob as consequências de ontem - você tem misericórdia fresca hoje.', 'Receba a misericórdia de Deus para este novo dia. Não carregue a culpa de ontem.', 'Senhor, obrigado porque Tuas misericórdias são novas nesta manhã. Eu as recebo. Amém.', 'Comece o dia agradecendo por 5 misericórdias', 'vida_crista', 'manha'),

('Transformados pela Palavra', '2026-08-18', 'Santifica-os na verdade; a tua palavra é a verdade.', 'João 17:17', 'A Palavra de Deus tem poder transformador. Ela não apenas informa, mas transforma. Esta manhã, alimente-se da Palavra esperando transformação, não apenas informação.', 'Você lê a Bíblia apenas para conhecimento ou para transformação? Leia hoje esperando mudança.', 'Pai, que Tua Palavra me transforme hoje. Não apenas quero saber, quero ser mudado. Amém.', 'Leia a Bíblia pedindo que Deus te transforme', 'vida_crista', 'manha'),

('Comunhão com Cristo', '2026-08-19', 'Permaneceiai em mim, e eu em vós; como a vara de si mesma não pode dar fruto, se não estiver na videira.', 'João 15:4', 'Vida cristã vitoriosa não vem de esforço, mas de conexão. Permanecer em Cristo não é um evento, é um estilo de vida. Quanto mais você permanece, mais fruto produz.', 'Como está sua comunhão com Cristo? Você está apenas ocupado "para" Ele ou permanecendo "com" Ele?', 'Jesus, ensina-me a permanecer em Ti. Que nossa comunhão seja profunda e constante. Amém.', 'Passe 30 minutos em comunhão sem pedir nada', 'vida_crista', 'manha'),

('Andando no Espírito', '2026-08-20', 'Andai em Espírito, e não cumprireis a concupiscência da carne.', 'Gálatas 5:16', 'A vida cristã é sobrenatural, não natural. Você não consegue viver em sua própria força. Quando anda no Espírito, Ele lhe dá poder sobre a carne.', 'Você está tentando viver a vida cristã em sua força ou no poder do Espírito?', 'Espírito Santo, enche-me e capacita-me. Não consigo em minha força. Amém.', 'Ore pedindo plenitude do Espírito hoje', 'vida_crista', 'manha'),

('Testemunhas de Cristo', '2026-08-21', 'Mas recebereis a virtude do Espírito Santo, que há de vir sobre vós; e ser-me-eis testemunhas.', 'Atos 1:8', 'Todo cristão é chamado a testemunhar. Não é sobre ter todas as respostas, mas compartilhar o que Cristo fez em você. Esta manhã, prepare-se para ser testemunha hoje.', 'Como você pode ser testemunha de Cristo hoje? Compartilhe sua fé com alguém.', 'Senhor, dá-me coragem e oportunidade para testemunhar de Ti hoje. Amém.', 'Compartilhe sua fé com pelo menos uma pessoa', 'vida_crista', 'manha'),

-- MULHERES - Tarde (30)
('Mulher Virtuosa', '2026-08-22', 'Mulher virtuosa quem a achará? O seu valor muito excede ao de rubis.', 'Provérbios 31:10', 'A mulher virtuosa não é perfeita, mas é dedicada. Ela teme ao Senhor e isso se reflete em todas as áreas da vida. Seu valor não está em aparência, mas em caráter.', 'Você está cultivando caráter ou apenas aparência? Invista no que é eterno.', 'Senhor, forma em mim um caráter virtuoso que Te glorifica. Amém.', 'Leia Provérbios 31 completo', 'mulheres', 'tarde'),

('Força e Dignidade', '2026-08-23', 'A força e a glória são as suas vestes, e ri-se do dia futuro.', 'Provérbios 31:25', 'Mulheres fortes não têm medo do futuro porque confiam em Deus. Sua força não vem de si mesma, mas do Senhor. Você pode rir do futuro quando sabe quem controla o amanhã.', 'Você está ansiosa com o futuro ou confiando em Deus? Escolha confiar hoje.', 'Pai, reveste-me de força e dignidade. Ensina-me a confiar no futuro que tens para mim. Amém.', 'Declare: "Eu confio no futuro que Deus tem para mim"', 'mulheres', 'tarde'),

('Mulheres que Oram', '2026-08-24', 'Mas Ana orava no seu coração.', '1 Samuel 1:13', 'Ana transformou sua dor em oração. Ela não se amargou, mas buscou a Deus intensamente. Mulheres de oração mudam gerações. Seu filho Samuel se tornou profeta e juiz.', 'Como está sua vida de oração? Você está levando tudo a Deus ou apenas reclamando?', 'Senhor, como Ana, eu derramo meu coração diante de Ti. Ouve minha oração. Amém.', 'Ore intensamente por algo que você deseja', 'mulheres', 'tarde'),

('Mulheres Corajosas', '2026-08-25', 'Naquele tempo Débora, profetisa, mulher de Lapidote, julgava a Israel.', 'Juízes 4:4', 'Débora foi juíza numa época dominada por homens. Deus não está limitado por gênero. Ele usa mulheres corajosas para liderar, profetizar e transformar nações.', 'Deus te chamou para algo que parece impossível? Seja corajosa como Débora.', 'Deus, dá-me coragem para cumprir o propósito que tens para minha vida. Amém.', 'Dê um passo corajoso em direção ao seu chamado', 'mulheres', 'tarde'),

('Beleza Interior', '2026-08-26', 'Não seja o vosso enfeite o exterior, mas o homem encoberto no coração; no incorruptível de um espírito manso e quieto.', '1 Pedro 3:3-4', 'Deus não condena beleza externa, mas prioriza beleza interior. Um espírito manso e quieto é precioso aos olhos de Deus. Invista mais no interior que no exterior.', 'Você gasta mais tempo e dinheiro no exterior ou no interior? Ajuste suas prioridades.', 'Senhor, que minha beleza seja primeiro interior. Forma em mim um espírito manso. Amém.', 'Invista tempo em beleza interior hoje (oração, Palavra)', 'mulheres', 'tarde'),

-- Continuando com mais 15 devocionais por categoria para completar 300...
